package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        CSVFormat result = format.withIgnoreEmptyLines(true);

        assertNotNull(result, "Resulting CSVFormat should not be null");
        assertTrue(result.getIgnoreEmptyLines(), "IgnoreEmptyLines should be true after calling withIgnoreEmptyLines(true)");
        // original format should remain unchanged (immutable)
        assertFalse(format.getIgnoreEmptyLines(), "Original CSVFormat's ignoreEmptyLines should remain false");
    }
}
